import { db } from './db';
import { cache } from './cache';
import { logger } from './logger';

export async function generateReport(userId, startDate, endDate, format, includeCharts, sendEmail, emailTo, compress, locale, timezone, filterInactive, sortBy) {
  // Fetch
  const user = await db.query('SELECT * FROM users WHERE id = $1', [userId]);
  const orders = await db.query('SELECT * FROM orders WHERE user_id = $1 AND date BETWEEN $2 AND $3', [userId, startDate, endDate]);
  if (filterInactive) {
    orders.rows = orders.rows.filter(o => o.active);
  }
  // Sort
  if (sortBy === 'date') orders.rows.sort((a, b) => a.date - b.date);
  else if (sortBy === 'amount') orders.rows.sort((a, b) => a.amount - b.amount);
  // Calculate
  let total = 0;
  let count = 0;
  for (const o of orders.rows) {
    total += o.amount;
    count++;
  }
  const avg = total / count;
  // Format
  let output;
  if (format === 'csv') {
    output = orders.rows.map(o => `${o.id},${o.amount},${o.date}`).join('\n');
  } else if (format === 'json') {
    output = JSON.stringify({ user: user.rows[0], orders: orders.rows, total, avg });
  } else {
    output = `Report for ${user.rows[0].name}: ${count} orders, total ${total}, avg ${avg}`;
  }
  // Charts
  if (includeCharts) {
    const chartData = orders.rows.map(o => ({ x: o.date, y: o.amount }));
    output += '\n' + JSON.stringify(chartData);
  }
  // Compress
  if (compress) output = await gzip(output);
  // Email
  if (sendEmail) await mailer.send(emailTo, 'Report', output);
  // Cache
  cache.set(`report:${userId}`, output);
  logger.info(`Report generated for ${userId}`);
  return output;
}
