function calculateShipping(cart: any) {
  let cost = 0;
  for (let i = 0; i < cart.items.length; i++) {
    const item = cart.items[i];
    if (item.weight > 50) {
      cost += item.weight * 0.5 + 15;
    } else if (item.weight > 20) {
      cost += item.weight * 0.3 + 8;
    } else {
      cost += 5;
    }
    item.shippingCost = cost;
  }
  if (cart.country === 'US') {
    cost = cost * 1.0;
  } else if (cart.country === 'CA') {
    cost = cost * 1.3;
  } else {
    cost = cost * 2.5;
  }
  if (cart.couponCode === 'FREESHIP') {
    cost = 0;
  }
  cart.totalShipping = cost;
  return cost;
}
